/**
 * Versioning — 340B Advocacy Dashboard (CEO-Ready Upgrade)
 * ==========================================================
 * Single place for dataset version and last-updated date.
 * Used by docs, change logs, and optional runtime checks.
 * Edit data/dataset-metadata.js and state-data.js CONFIG; this file reads from globals.
 *
 * NOVICE: Do not edit this file for content. Update lastUpdated and datasetVersion
 * in data/dataset-metadata.js (and CONFIG in state-data.js) when you change data.
 */
(function (global) {
  "use strict";

  function getVersion() {
    if (typeof DATASET_METADATA !== "undefined" && DATASET_METADATA && DATASET_METADATA.datasetVersion) {
      return DATASET_METADATA.datasetVersion;
    }
    if (typeof CONFIG !== "undefined" && CONFIG && CONFIG.lastUpdated) {
      return "1.0";
    }
    return "1.0";
  }

  function getLastUpdated() {
    if (typeof DATASET_METADATA !== "undefined" && DATASET_METADATA && DATASET_METADATA.lastUpdated) {
      return DATASET_METADATA.lastUpdated;
    }
    if (typeof CONFIG !== "undefined" && CONFIG && CONFIG.lastUpdated) {
      return CONFIG.lastUpdated;
    }
    return "March 2025";
  }

  function getDatasetName() {
    if (typeof DATASET_METADATA !== "undefined" && DATASET_METADATA && DATASET_METADATA.name) {
      return DATASET_METADATA.name;
    }
    return "340B State Law & Community Benefit";
  }

  var VERSIONING = {
    getVersion: getVersion,
    getLastUpdated: getLastUpdated,
    getDatasetName: getDatasetName
  };

  if (typeof global !== "undefined") {
    global.VERSIONING = VERSIONING;
  }
})(typeof window !== "undefined" ? window : this);
